object You {
  lateinit var meeting: Unit
}

fun main() {
  You.meeting
}

type Tomorrow = never;

function wait(): Tomorrow {
  while (true) {}
}

const arrival: Tomorrow = wait();

CREATE TABLE everyone (
  id INT PRIMARY KEY
);
CREATE TABLE beloved (
  id INT REFERENCES everyone(id)
);

SELECT everyone.id,
       beloved.id AS beside
  FROM everyone
  LEFT JOIN beloved
    ON everyone.id = beloved.id;
